                <button
                    type="button"
                    onClick={() => accordionRef.current?.expandAll()}
                    className="px-4 py-2 bg-blue-50 text-blue-600 rounded-md font-medium text-sm hover:bg-blue-100 transition-colors">Expand All
                              </button>
                <button
                    type="button"
                    onClick={() => accordionRef.current?.collapseAll()}
                    className="px-4 py-2 bg-gray-50 text-gray-600 rounded-md font-medium text-sm hover:bg-gray-100 transition-colors">Collapse All
                              </button>
            </div>
            <Accordion ref={accordionRef} allowMultiple variant="bordered">
                <AccordionItem id="ctrl-1" title="Initial Setup">Configure your development environment and install necessary dependencies before beginning.
